const fn sb_p313(b: u8) -> Sb {
    match b {
        0x00..=0x4a => Sb::OLetter,
        0x50..=0xff => Sb::OLetter,
        _ => Sb::Other,
    }
}

#[cfg(feature = "full")]
const fn sb_p334(b: u8) -> Sb {
    match b {
        0x00..=0x79 => Sb::OLetter,
        _ => Sb::Other,
    }
}

#[cfg(feature = "full")]
const fn sb_pe00(b: u8) -> Sb {
    match b {
        0x01 => Sb::Format,
        0x20..=0x7f => Sb::Extend,
        _ => Sb::Other,
    }
}

#[cfg(feature = "full")]
const fn sb_pe01(b: u8) -> Sb {
    match b {
        0x00..=0xef => Sb::Extend,
        _ => Sb::Other,
    }
}

